const item = $input.first();
const data = item.json;

// Soporte para ambos formatos: {query: {...}} y campos planos
const query = (data.query && typeof data.query === 'object') ? data.query : data;
const especialistaRaw = (query.especialista || data.especialista || '').toLowerCase();
const fecha = query.fecha || data.fecha || '';

// Normalizar acentos (ó→o, é→e, etc.)
const normalizar = (s) => s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const especialista = normalizar(especialistaRaw);

// Mapa de especialistas → eventTypeId de Cal.com
const ESPECIALISTAS = {
  garcia: 4857668,
  lopez: 4857681,
  martinez: 4857683,
};

let eventTypeId = null;
for (const [key, id] of Object.entries(ESPECIALISTAS)) {
  if (especialista.includes(key)) {
    eventTypeId = id;
    break;
  }
}

if (!eventTypeId) {
  return [{ json: { error: `Especialista no reconocido: ${especialistaRaw}`, fecha, disponible: false } }];
}

return [{ json: { eventTypeId, fecha } }];

const item = $input.first();
const data = item.json;

// Si hay error del nodo anterior (especialista no reconocido)
if (data.error) {
  return [{ json: data }];
}

// La respuesta de Cal.com v2 tiene: data.slots = { "2025-10-09": [{time: "..."}] }
const slots = data.data?.slots || {};
const fecha = Object.keys(slots)[0] || '';
const horarios = (slots[fecha] || []).map(s => s.time.substring(11, 16)); // HH:MM

return [{
  json: {
    disponible: horarios.length > 0,
    fecha,
    horarios,
    total: horarios.length
  }
}];
